css_snippet:
:root {
  --bg: #f5f5f0;
  --text: #0a0a0a;
  --accent: #ff3300;
  --surface: #e8e8e3;

  --font-h: 'Space Grotesk', 'Arial Black', sans-serif;
  --font-b: 'Inter', Helvetica, sans-serif;
}

body {
  background: var(--bg);
  color: var(--text);
  font-family: var(--font-b);
}

h1 {
  font-family: var(--font-h);
  font-weight: 800;
  font-size: clamp(56px, 9vw, 140px);
  line-height: 0.95;
  letter-spacing: -0.03em;
}

h2 {
  font-family: var(--font-h);
  font-weight: 700;
  font-size: clamp(36px, 5vw, 80px);
  line-height: 1.0;
  letter-spacing: -0.02em;
}
